	(1741,'_transient_dash_3605f57d6641b1f6504fce9d39bcf566','<div class=\"rss-widget\"><ul><li><a class=\'rsswidget\' href=\'https://wordpress.org/news/2017/06/evans/\'>WordPress 4.8 “Evans”</a> <span class=\"rss-date\">8 junio, 2017</span><div class=\"rssSummary\">An Update with You in Mind Gear up for a more intuitive WordPress! Version 4.8 of WordPress, named “Evans” in honor of jazz pianist and composer William John “Bill” Evans, is available for download or update in your WordPress dashboard. New features in 4.8 add more ways for you to express yourself and represent your brand. Though some [&hellip;]</div></li></ul></div><div class=\"rss-widget\"><ul><li><a class=\'rsswidget\' href=\'https://ma.tt/2017/06/heroin-or-aspirin/\'>Matt: Heroin or Aspirin</a></li><li><a class=\'rsswidget\' href=\'https://buddypress.org/2017/06/buddypress-2-9-0-beta-2/\'>BuddyPress: BuddyPress 2.9.0 Beta 2</a></li><li><a class=\'rsswidget\' href=\'https://wptavern.com/gutenberg-0-2-0-released-adds-new-custom-html-and-cover-image-blocks\'>WPTavern: Gutenberg 0.2.0 Released, Adds New Custom HTML and Cover Image Blocks</a></li></ul></div><div class=\"rss-widget\"><ul><li class=\"dashboard-news-plugin\"><span>Plugin popular:</span> WooCommerce&nbsp;<a href=\"plugin-install.php?tab=plugin-information&amp;plugin=woocommerce&amp;_wpnonce=693dfbd8da&amp;TB_iframe=true&amp;width=600&amp;height=800\" class=\"thickbox open-plugin-details-modal\" aria-label=\"Instalar WooCommerce\">(Instalar)</a></li></ul></div>','no'),
