	(744,203,'repeatable_fields_2','a:2:{i:0;a:5:{s:13:\"texto_espanol\";s:99:\"Ixik Uh recibe la falda, [el pronóstico es] hijos de mujer, hijos de hombre, es decir, fertilidad.\";s:6:\"img_hp\";s:7:\"4_1.png\";s:10:\"texto_maya\";s:40:\"<i>uk\'am upik Ixik Uh, yal [u]ne[n]</i>.\";s:12:\"coordenada_x\";s:3:\"178\";s:12:\"coordenada_y\";s:1:\"1\";}i:1;a:5:{s:13:\"texto_espanol\";s:55:\"Kiimil la falda abrocha, [el pronóstico es] mortandad.\";s:6:\"img_hp\";s:7:\"4_2.png\";s:10:\"texto_maya\";s:36:\"<i>upik uk\'al Ukiimil, cham[a]l</i>.\";s:12:\"coordenada_x\";s:3:\"427\";s:12:\"coordenada_y\";s:1:\"1\";}}'),
