	(917,218,'id_seccion','b'),
	(918,218,'id_notas','<p>El almanaque inicia con la columna de días <i> &ltchuen, akbal, men, manik&gt </i> y <i>  &ltcauac&gt </i>, todos con el mismo coeficiente rojo 8. A la fecha <i> &lt8 chuen&gt</i> le corresponde este augurio.</p>'),
	(919,218,'id_tematica','Almanaques misceláneos serie II'),
	(920,219,'_post_template','Seccion_Hotspot_A.php'),
