	(1341,274,'id_notas','<p>La diosa carga el rostro de la muerte.</p>         <p>La diosa I tiene una diadema de flores y carga sobre la espalda el difrasismo de la riqueza: <i>ya\'ax-k\'an</i>, “lo verde-lo amarillo”. El augurio es favorable.</p>'),
	(1342,274,'id_tematica','Almanaques de la diosa lunar'),
	(1343,274,'repeatable_fields_2','a:2:{i:0;a:5:{s:13:\"texto_espanol\";s:72:\"la gran muerte blanca es la carga de Ixik Uh, [el augurio es] mortandad.\";s:6:\"img_hp\";s:8:\"42_1.png\";s:10:\"texto_maya\";s:50:\"<i>sak chak cham[ii]y ukuch Ixik Uh, cham[a]l</i>.\";s:12:\"coordenada_x\";s:3:\"288\";s:12:\"coordenada_y\";s:1:\"1\";}i:1;a:5:{s:13:\"texto_espanol\";s:64:\"la riqueza es su carga, [el augurio son] elotes(?), alimento(?).\";s:6:\"img_hp\";s:8:\"42_2.png\";s:10:\"texto_maya\";s:47:\"<i>uya\'ax [u]k\'an ukuch, ahan(?), o\'och(?)</i>.\";s:12:\"coordenada_x\";s:3:\"414\";s:12:\"coordenada_y\";s:1:\"1\";}}'),
