	(1464,275,'repeatable_fields_2','a:2:{i:0;a:5:{s:13:\"texto_espanol\";s:46:\"el pago de Ixik Uh, Sak Ixik, es mucha comida.\";s:6:\"img_hp\";s:8:\"43_1.png\";s:10:\"texto_maya\";s:46:\"<i>yat[aa]l Ixik Uh, Sak Ixik, ox wi\'[il]</i>.\";s:12:\"coordenada_x\";s:3:\"293\";s:12:\"coordenada_y\";s:2:\"10\";}i:1;a:5:{s:13:\"texto_espanol\";s:43:\"el pago de Ixik Uh, Sak Ixik, es mortandad.\";s:6:\"img_hp\";s:8:\"43_2.png\";s:10:\"texto_maya\";s:45:\"<i>yat[aa]l Ixik Uh, Sak Ixik, Kiiml[a]l</i>.\";s:12:\"coordenada_x\";s:3:\"421\";s:12:\"coordenada_y\";s:2:\"10\";}}'),
