	(1526,259,'repeatable_fields_2','a:1:{i:0;a:5:{s:13:\"texto_espanol\";s:236:\"Dios C o K\'uh, personaje que al parecer personifica la esencia misma de la divinidad o sacralidad (Ringle, 1988), representado a su vez sobre un fondo rojo, símbolo de la sangre, del oiente, del renacimiento y del mundo de los muertos.\";s:10:\"texto_maya\";s:0:\"\";s:6:\"img_hp\";s:0:\"\";s:12:\"coordenada_x\";s:0:\"\";s:12:\"coordenada_y\";s:0:\"\";}}'),
