	(1823,279,'repeatable_fields_2','a:1:{i:0;a:2:{s:13:\"texto_espanol\";s:307:\"Dios L o Ha’al Ik’ Mam, \'Abuelo Materno Negro de la Lluvia\', dios del inframundo, la destrucción, la riqueza y el cielo nocturno. Aparece sobre un fondo mitad rojo y mitad amarillo. Entidad compleja y ambivalente asociada tanto con el Inframundo y la destrucción, como con la riqueza (ver Taube, 1992)\";s:6:\"img_hp\";s:0:\"\";}}'),
