	(2017,294,'repeatable_fields_2','a:1:{i:0;a:5:{s:13:\"texto_espanol\";s:325:\"Una versión femenina de Itzamna’ (señor supremo del panteón maya), con uno de sus pechos visibles, cuya serpiente enrollada sobre la cabeza simboliza el proceso cíclico de la naturaleza -tal vez aluda de algún modo a las fases lunares-, así como un huso provisto con hilo, que sugiere que es señora de las tejedoras.\";s:10:\"texto_maya\";s:0:\"\";s:6:\"img_hp\";s:0:\"\";s:12:\"coordenada_x\";s:0:\"\";s:12:\"coordenada_y\";s:0:\"\";}}'),
