	(2173,307,'repeatable_fields_2','a:1:{i:0;a:2:{s:13:\"texto_espanol\";s:169:\"Esta es una versión envejecida del dios H del viento y de las flores. Con un yelmo semejante a la cabeza del dios de la lluvia Chaak, sostiene una flor entre sus manos.\";s:6:\"img_hp\";s:0:\"\";}}'),
