	(2245,313,'repeatable_fields_2','a:1:{i:0;a:2:{s:13:\"texto_espanol\";s:363:\"Las deidades representadas aquí son el dios E del maíz o Ahan(?); el H o Ik’(?), numen del viento, de las flores, de las fragancias, vapores (<i>oox</i>) y del número 3 (<i>ox</i>); y finalmente el A o Kiimil, señor de la muerte, la descomposición y la decadencia, con un tocado que combina elementos de insecto y de reptil, símbolo del ámbito telúrico.\";s:6:\"img_hp\";s:0:\"\";}}'),
