	(2510,329,'repeatable_fields_2','a:1:{i:0;a:2:{s:13:\"texto_espanol\";s:321:\"El dios M o Éek\' Chuwaaj, \'Alacrán Negro \', de los mercaderes y del comercio, Ik’ Chuwaaj (en lenguas cholanas), quien camina con su típico bastón de viajero y lleva sobre la espalda la misma carga que la diosa Ixik Uh: ‘alimento’, expresado a través del tamal/tortilla (<i>waaj</i>) y del agua (<i>ha’</i>).\";s:6:\"img_hp\";s:0:\"\";}}'),
