	(2522,330,'repeatable_fields_2','a:1:{i:0;a:2:{s:13:\"texto_espanol\";s:147:\"En la viñeta aparece el dios M del comercio, Ik’ Chuwaaj, con pintura corporal negra en su cuerpo; parece sostener un hueso con la mano derecha.\";s:6:\"img_hp\";s:0:\"\";}}'),
