	(2641,340,'id_tematica',''),
	(2642,340,'repeatable_fields_2','a:1:{i:0;a:5:{s:13:\"texto_espanol\";s:332:\"La diosa I también se llama Sak Ixik. Lo sabemos no a causa del texto, pues no se ha conservado casi nada, sino porque lleva sobre su cabeza el signo sak, ‘blanco’. Aquí no sostiene nada sobre las manos, sino que adopta el ademán de pesar o dolor ante la muerte, que consiste como vimos en llevar una mano cerca de la frente.\";s:10:\"texto_maya\";s:0:\"\";s:6:\"img_hp\";s:0:\"\";s:12:\"coordenada_x\";s:0:\"\";s:12:\"coordenada_y\";s:0:\"\";}}'),
