	(2666,342,'id_tematica',''),
	(2667,342,'repeatable_fields_2','a:1:{i:0;a:2:{s:13:\"texto_espanol\";s:367:\"A la izquierda la diosa I o Ixik Uh, \'Mujer de la Luna\', carga el difrasismo ‘verde-amarillo’ en señal de riqueza. En la segunda viñeta la diosa carga a la pequeña ave <i>muy</i>, de presagios inframundanos y mortales; observar que el pájaro muy está descarnado y usa una collera con globos oculares humanos. Finalmente la diosa carga el rostro de la muerte.\";s:6:\"img_hp\";s:0:\"\";}}'),
	(2680,358,'repeatable_fields_2','a:4:{i:0;a:5:{s:13:\"texto_espanol\";s:57:\"xik llegó, es el pago de Ik\' Mam, tronos(?) de señores.\";s:6:\"img_hp\";s:8:\"49_1.png\";s:10:\"texto_maya\";s:52:\"<i>hul[i] Ixik, yat[aa]l Ik\' Mam, tz\'am(?) ajaw</i>.\";s:12:\"coordenada_x\";s:3:\"237\";s:12:\"coordenada_y\";s:1:\"1\";}i:1;a:5:{s:13:\"texto_espanol\";s:49:\"Ixik llegó, es el pago del perro, es su anuncio.\";s:6:\"img_hp\";s:8:\"49_2.png\";s:10:\"texto_maya\";s:42:\"<i>hul[i] Ixik, yat[aa]l tzul, umu\'uk</i>.\";s:12:\"coordenada_x\";s:3:\"319\";s:12:\"coordenada_y\";s:1:\"1\";}i:2;a:5:{s:13:\"texto_espanol\";s:52:\"Ixik llegó, es el pago del armadillo, mucha comida.\";s:6:\"img_hp\";s:8:\"49_3.png\";s:10:\"texto_maya\";s:47:\"<i>hul[i] Ixik, yat[aa]l ibach, ox wi\'[il]</i>.\";s:12:\"coordenada_x\";s:3:\"470\";s:12:\"coordenada_y\";s:1:\"1\";}i:3;a:5:{s:13:\"texto_espanol\";s:57:\"Ixik llegó, es el pago de Kan Chij Winkil(?), mortandad.\";s:6:\"img_hp\";s:8:\"49_4.png\";s:10:\"texto_maya\";s:60:\"<i>hul[i] Ixik, yat[aa]l Kan Chi[j] Winkil(?), cham[a]l</i>.\";s:12:\"coordenada_x\";s:3:\"542\";s:12:\"coordenada_y\";s:1:\"1\";}}'),
