	(2716,346,'repeatable_fields_2','a:1:{i:0;a:5:{s:13:\"texto_espanol\";s:369:\"La diosa  I, lxik Uh, \'Señora de la Luna\' o Sak Ixik, \'Mujer Blanca\', parece entablar una relación cariñosa con el dios H del viento y de las flores. Thompson (1972) describe sus lenguajes corporales admirablemente: “sentada […] con las piernas entrelazadas […] para representar el coito. El dios le rodea el cuello con la mano; ella le acaricia el mentón”.\";s:10:\"texto_maya\";s:0:\"\";s:6:\"img_hp\";s:0:\"\";s:12:\"coordenada_x\";s:0:\"\";s:12:\"coordenada_y\";s:0:\"\";}}'),
