	(2740,348,'repeatable_fields_2','a:1:{i:0;a:2:{s:13:\"texto_espanol\";s:176:\"La diosa I o lxik Uh, \'Señora de la Luna\', tiene una diadema de flores y carga sobre la espalda el difrasismo de la riqueza: <i>ya’ax-k’an</i>, ‘lo verde-lo amarillo’.\";s:6:\"img_hp\";s:0:\"\";}}'),
