	(2946,361,'repeatable_fields_2','a:1:{i:0;a:2:{s:13:\"texto_espanol\";s:236:\"La diosa joven I o lxik Uh, \'Señora de la Luna\', se involucra cercanamente con el cadáver descarnado del dios A o Kiimil, numen de la muerte; la segunda escena produce ansiedad, pues parece que la diosa está padeciendo ese encuentro.\";s:6:\"img_hp\";s:0:\"\";}}'),
