	(2994,365,'repeatable_fields_2','a:1:{i:0;a:2:{s:13:\"texto_espanol\";s:195:\"La diosa I o lxik Uh, \'Señora de la Luna\', se sienta frente al señor de la muerte A o Kiimil; las piernas de ambos están ligeramente yuxtapuestas, lo que quizá insinúe una relación amorosa.\";s:6:\"img_hp\";s:0:\"\";}}'),
