	(3128,375,'repeatable_fields_2','a:1:{i:0;a:2:{s:13:\"texto_espanol\";s:214:\"Tal como se insinúa en este texto jeroglífico, el dios E del maíz o Ahan(?), ‘Elote’, es la víctima de los dardos de Tawiskal. Por ello aparece en la viñeta inferior de esta página, herido por una flecha.\";s:6:\"img_hp\";s:0:\"\";}}'),
