	(3163,378,'id_tematica',''),
	(3164,378,'repeatable_fields_2','a:1:{i:0;a:2:{s:13:\"texto_espanol\";s:402:\"Tal como se insinúa en este texto, la espalda(?) de una tortuga fue perforada con las flechas de luz del planeta. Por ello aparece en la viñeta inferior un anfibio que tiene cuando menos algunos atributos de galápago. A decir de Thompson (1972) los quelonios son “portadores de la lluvia”, además se que la tierra cultivable era representada en el arte maya desde antaño como una gran tortuga.\";s:6:\"img_hp\";s:0:\"\";}}'),
	(3165,378,'_wp_old_slug','deidades-d121b-2'),
	(3166,379,'_post_template','Seccion_Hotspot_B.php'),
	(3167,379,'id_correo',NULL),
	(3168,379,'id_usuario',NULL),
	(3169,379,'id_IDhotspots',NULL),
	(3170,379,'id_imagen_zoom_1','deidades_encuadres/d123a.png'),
