	(3261,386,'repeatable_fields_2','a:1:{i:0;a:2:{s:13:\"texto_espanol\";s:318:\"Hallamos aquí una dramática escena donde el Sol se encuentra atravesado por dos largos punzones de hueso, mientras que su fondo es mitad blanco (día) y mitad negro (noche) en señal de ocultamiento. Y debajo del conjunto hallamos una serpiente voraz que pienso representa al planeta Venus intentando comerse al Sol.\";s:6:\"img_hp\";s:0:\"\";}}'),
