	(3569,407,'repeatable_fields_2','a:1:{i:0;a:2:{s:13:\"texto_espanol\";s:340:\"Apreciamos a Chaak en actitud de caminar; lleva un pectoral sobre el pecho que consta del signo <i>ya’ax</i>, ‘azul/verde’; con su mano izquierda sostiene el hacha-relámpago, que podría ser el cetro del dios K’awiil, mientras que sobre la palma derecha extendida tiene una bolsa de comida de la que pende una flor (quizá ninfea).\";s:6:\"img_hp\";s:0:\"\";}}'),
