	(3617,411,'repeatable_fields_2','a:1:{i:0;a:2:{s:13:\"texto_espanol\";s:281:\"Un Chaak caminante con báculo de viajero carga tortillas secas con frijoles molidos (<i>sukuk</i>) sobre la espalda, al tiempo que se desplaza sobre un camino. Como dice Markus Eberl (2001), se trata de alimentos sencillos y sin condimentar, que eran adecuados para largos viajes.\";s:6:\"img_hp\";s:0:\"\";}}'),
