	(3677,418,'repeatable_fields_2','a:5:{i:0;a:5:{s:13:\"texto_espanol\";s:208:\"la Gran Estrella Lajun Chan se manifestó en el este; el gran tigrillo es su[víctima] flechada, es el anuncio del corazón del dios, señores nagualistas heridos, muchos dardos sagrados, tortugas(?) dolidas.\";s:10:\"texto_maya\";s:142:\"<i>k’al[a]j lak’in Lajun Chan Chak Ek’; chak bolay ujul, umu’uk yo’hl k’uh, yaj wahy[i]s ajaw, ox k’uh[ul] jul, yaj paat(?)</i>.\";s:6:\"img_hp\";s:9:\"60_1d.png\";s:12:\"coordenada_x\";s:3:\"148\";s:12:\"coordenada_y\";s:1:\"4\";}i:1;a:5:{s:13:\"texto_espanol\";s:71:\"En] <3 zodz> la Gran Estrella Kiimil  [ya se había alzado] en el este.\";s:10:\"texto_maya\";s:49:\"<i>3 suutz\' [tzeniiy] Kiimil Chak Ek\' lak\'in</i>.\";s:6:\"img_hp\";s:8:\"60_5.png\";s:12:\"coordenada_x\";s:1:\"4\";s:12:\"coordenada_y\";s:3:\"234\";}i:2;a:5:{s:13:\"texto_espanol\";s:78:\"[En] <13 mol> la Gran Estrella “ave” [ya se había levantado] en el norte.\";s:10:\"texto_maya\";s:41:\"<i>13 mol [tzeniiy] … Chak Ek\' nal</i>.\";s:6:\"img_hp\";s:8:\"60_6.png\";s:12:\"coordenada_x\";s:2:\"38\";s:12:\"coordenada_y\";s:3:\"234\";}i:3;a:5:{s:13:\"texto_espanol\";s:70:\"[En] <18 uo> la Gran Estrella Ahkan [ya había ascendido] en el oeste.\";s:10:\"texto_maya\";s:49:\"<i>18 ik\'at [tzeniiy] Ahkan Chak Ek\' chik\'in</i>.\";s:6:\"img_hp\";s:8:\"60_7.png\";s:12:\"coordenada_x\";s:2:\"72\";s:12:\"coordenada_y\";s:3:\"234\";}i:4;a:5:{s:13:\"texto_espanol\";s:84:\"[En] <6 zip> la Gran Estrella Oxlajun Ka\'an Winkil [ya se había elevado] en el sur.\";s:10:\"texto_maya\";s:68:\"<i>6 chakat [tzeniiy] Oxlajun Ka’an Winkil Chak Ek’ noh[ol].</i>\";s:6:\"img_hp\";s:8:\"60_8.png\";s:12:\"coordenada_x\";s:3:\"106\";s:12:\"coordenada_y\";s:3:\"234\";}}'),
