	(3798,425,'repeatable_fields_2','a:1:{i:0;a:2:{s:13:\"texto_espanol\";s:279:\"Apreciamos a Chaak de pie sobre un cuerpo de agua que contiene conchas, caracolas y peces. Thompson (1972) sospecha que se trata del mar. El dios B sostiene su hacha con la mano izquierda, mientras que con la derecha levanta una ninfea de tallo largo, mismo que procede del agua.\";s:6:\"img_hp\";s:0:\"\";}}'),
