	(3972,454,'id_notas','<p>Traduzco por ‘riqueza’ el difrasismo <i>uya’ax uk’an</i>, ‘lo verde, lo amarillo’ (expresión que se encuentra en varias lenguas mayances), y cabe mencionar que “bajarán las sogas y cuerdas; del cielo bajará la fuerza”, es una metáfora que se usa en los libros de Chilam Balam y que equivale más o menos a la llegada del destino.'),
	(3973,454,'id_tematica','Tabla del planeta Venus'),
	(3974,454,'repeatable_fields_2','a:1:{i:0;a:5:{s:13:\"texto_espanol\";s:134:\"[durante] diez lunas, diez veintenas, su anuncio es riqueza, es la fama de la cuerda blanca, es la nueva de los extranjeros del oeste.\";s:6:\"img_hp\";s:9:\"70_1d.png\";s:10:\"texto_maya\";s:92:\"<i>lajun uh, [lajun] winal, umu\'uk uya\'ax [u]k\'an, umu\'uk sak tab, umu\'uk tz\'ul chik\'in</i>.\";s:12:\"coordenada_x\";s:3:\"240\";s:12:\"coordenada_y\";s:1:\"1\";}}'),
