	(3986,455,'id_notas',' <p><i><4 ahau 8 cumku, 12 lamat></i> alude a una fecha mítica que tuvo lugar ocho dias después del inicio de la creación del mundo vigente, es decir el 16 de septiembre de 3114 a.C. según el calendario juliano. El resto de la sección a de esta página se compone de cuatro columnas de jeroglíficos y números (a) (b) (c) (d),  los textos seguramente son augurios o pronósticos, aunque se encuentran muy dañados y casi no se pueden entender ya.</p>'),
	(3987,455,'id_tematica','Tabla lunar o de los eclipses solares'),
	(3988,455,'repeatable_fields_2','a:5:{i:0;a:5:{s:13:\"texto_espanol\";s:56:\"&lt4 ahau 8 cumku, 12 lamat&gt ocho días desde el agua.\";s:10:\"texto_maya\";s:46:\"<i>4 ajaw 8 bixo\'hl, 12 ek\' 8 k\'in ti ha\'</i>.\";s:6:\"img_hp\";s:8:\"71_0.png\";s:12:\"coordenada_x\";s:3:\"264\";s:12:\"coordenada_y\";s:1:\"1\";}i:1;a:5:{s:13:\"texto_espanol\";s:23:\"siete… pies sagrados.\";s:10:\"texto_maya\";s:27:\"<i>wuk… k\'uh[ul] ook</i>.\";s:6:\"img_hp\";s:8:\"71_a.png\";s:12:\"coordenada_x\";s:3:\"334\";s:12:\"coordenada_y\";s:1:\"1\";}i:2;a:5:{s:13:\"texto_espanol\";s:17:\"se puso de pie…\";s:10:\"texto_maya\";s:18:\"<i>… wa\'laj</i>.\";s:6:\"img_hp\";s:8:\"71_b.png\";s:12:\"coordenada_x\";s:3:\"388\";s:12:\"coordenada_y\";s:1:\"1\";}i:3;a:5:{s:13:\"texto_espanol\";s:15:\"… saakxaj(?).\";s:10:\"texto_maya\";s:22:\"<i>… saakxaj(?)</i>.\";s:6:\"img_hp\";s:8:\"71_c.png\";s:12:\"coordenada_x\";s:3:\"442\";s:12:\"coordenada_y\";s:1:\"1\";}i:4;a:5:{s:13:\"texto_espanol\";s:9:\"…, u…\";s:10:\"texto_maya\";s:16:\"<i>…, u...</i>\";s:6:\"img_hp\";s:8:\"71_d.png\";s:12:\"coordenada_x\";s:3:\"493\";s:12:\"coordenada_y\";s:1:\"1\";}}'),
