	(4645,503,'repeatable_fields_2','a:1:{i:0;a:2:{s:13:\"texto_espanol\";s:263:\"Esta es la primer viñeta de los portadores <<i>edznab</i>>. Chaak, dios de la lluvia, se encuentra de pie, en posición de caminar. Sostiene una antorcha encendida, que generalmente es símbolo de sequía, aunque el pronóstico escrito arriba no es desfavorable.\";s:6:\"img_hp\";s:0:\"\";}}'),
