	(4885,523,'repeatable_fields_2','a:1:{i:0;a:5:{s:13:\"texto_espanol\";s:186:\"El dios aparece sentado confortablemente dentro de su casa. Y si mi hipótesis es correcta, lo que Chaak crea es simplemente el destino o pronóstico de cada día del <i>tzolk’iin</i>.\";s:10:\"texto_maya\";s:0:\"\";s:6:\"img_hp\";s:0:\"\";s:12:\"coordenada_x\";s:0:\"\";s:12:\"coordenada_y\";s:0:\"\";}}'),
