	(5061,579,'repeatable_fields_2','a:5:{i:0;a:5:{s:13:\"texto_espanol\";s:111:\"[en] … 13 kéej las extremidades inferiores sagradas de Chaak Destructor se pusieron de pie; dividir tiempos.\";s:10:\"texto_maya\";s:70:\"<i>… 13 chaksijo’m wa’laj k’uh[ul] ook Muxib Chaak; tzil. </i>\";s:6:\"img_hp\";s:9:\"r2_1a.png\";s:12:\"coordenada_x\";s:1:\"4\";s:12:\"coordenada_y\";s:1:\"4\";}i:1;a:5:{s:13:\"texto_espanol\";s:113:\"[en] … 12/17 … las extremidades inferiores sagradas de Chaak y U’ Ixik se pusieron de pie; dividir tiempos.\";s:10:\"texto_maya\";s:65:\"<i>… 12/17 … wa’laj k’uh[ul] ook Ixik Uh Chaak; tzil.</i>\";s:6:\"img_hp\";s:9:\"r2_2a.png\";s:12:\"coordenada_x\";s:2:\"35\";s:12:\"coordenada_y\";s:1:\"4\";}i:2;a:5:{s:13:\"texto_espanol\";s:110:\"[en] … 7 kéej las extremidades inferiores sagradas de Chaak Destructor se pusieron de pie; dividir tiempos.\";s:10:\"texto_maya\";s:70:\"<i>… 7 chaksijo’m wa’laj k’uh[ul] ook [Mu]xib Chaak; tzil.</i>\";s:6:\"img_hp\";s:9:\"r2_3a.png\";s:12:\"coordenada_x\";s:2:\"88\";s:12:\"coordenada_y\";s:1:\"4\";}i:3;a:5:{s:13:\"texto_espanol\";s:115:\"[en] … 13 xul las extremidades inferiores sagradas de U’ Ixik [y de] Chaak se pusieron de pie; dividir tiempos.\";s:10:\"texto_maya\";s:71:\"<i>… 13 chi’ikin wa’laj k’uh[ul] ook U’ Ixik Chaak; tzil</i>.\";s:6:\"img_hp\";s:9:\"r2_4a.png\";s:12:\"coordenada_x\";s:3:\"132\";s:12:\"coordenada_y\";s:1:\"4\";}i:4;a:5:{s:13:\"texto_espanol\";s:102:\"[en] ... 13 imix 9 woo’ las extremidades inferiores sagradas de Chaak Destructor se pusieron de pie.\";s:10:\"texto_maya\";s:70:\"<i>... 13 [imox] 9 ik’[a]t wa’laj k’uh[ul] ook Muxib Chaahk.</i>\";s:6:\"img_hp\";s:9:\"r2_5a.png\";s:12:\"coordenada_x\";s:3:\"168\";s:12:\"coordenada_y\";s:1:\"4\";}}'),
