	(5085,548,'repeatable_fields_2','a:1:{i:0;a:2:{s:13:\"texto_espanol\";s:279:\"En la escena aparece Chaak hundido hasta los tobillos en un way o cavidad subterránea llena de agua. Tiene la cabeza virada hacia arriba en probable gesto de desear salir. Puede apreciarse además que Chaak porta una olla o vasija invertida a la altura del pubis o bajo vientre.\";s:6:\"img_hp\";s:0:\"\";}}'),
