	(5377,571,'repeatable_fields_2','a:1:{i:0;a:2:{s:13:\"texto_espanol\";s:257:\"En la imagen aparece Chaak avanzando con un bastón plantador. Sigo a Schele y Grube (1997) en su lectura del bloque jeroglífico <i>hi’inaj(?)</i>, ‘semilla’, pues aunque de momento es muy dudosa, al menos hace sentido en los contextos donde aparece.\";s:6:\"img_hp\";s:0:\"\";}}'),
