	(5583,586,'repeatable_fields_2','a:1:{i:0;a:2:{s:13:\"texto_espanol\";s:273:\"En la imagen aparece Chaak sentado sobre el número 20 y sobre el jeroglífico de <i>kab</i>, ‘tierra’. Frente a él tiene un incensario. En la parte superior del incensario apreciamos el signo silábico <b>po</b>, que sin duda evoca la palabra <i>pom</i>, ‘copal’.\";s:6:\"img_hp\";s:0:\"\";}}'),
