	(5659,592,'id_imagen_zoom_1','deidades_encuadres/d257b.png'),
	(5660,592,'id_imagen_zoom_2',NULL),
	(5661,592,'id_lamina','41'),
	(5662,592,'id_escriba',''),
	(5663,592,'id_seccion','b'),
	(5664,592,'id_notas',''),
	(5665,592,'id_tematica',''),
	(5666,592,'repeatable_fields_2','a:1:{i:0;a:5:{s:13:\"texto_espanol\";s:444:\"En la imagen aparece Chaak sentado bajo la lluvia con su capa de orlas ondulantes. En su tocado tiene el jeroglífico de ‘tamal’ o ‘tortilla’, sobre el cual surgen hojas tiernas de maíz. Igual que en el <i>t’o’ol</i> anterior, resulta interesante cómo se funden las identidades (imágenes y textos) del dios B o Chaak y del dios N o Itzam [K\'an] Aak, un fenómeno que ha sido llamado teosíntesis por Simon Martin (2015: 210-218).\";s:10:\"texto_maya\";s:0:\"\";s:6:\"img_hp\";s:0:\"\";s:12:\"coordenada_x\";s:0:\"\";s:12:\"coordenada_y\";s:0:\"\";}}'),
