	(5701,595,'id_tematica',''),
	(5702,595,'repeatable_fields_2','a:1:{i:0;a:2:{s:13:\"texto_espanol\";s:200:\"En esta imagen se ubica por principio en la fecha <2 <i>ahau</i>>. En ella aparece Chaak pintado de azul y sentado sobre el techo de una casa. En los muros de la misma está escrita la cifra negra 39.\";s:6:\"img_hp\";s:0:\"\";}}'),
