	(5912,612,'repeatable_fields_2','a:1:{i:0;a:2:{s:13:\"texto_espanol\";s:208:\"En la imagen se aprecia a la “bestia de Marte” o Aak(?) cortada, es decir sólo se observa la mitad de su talle, pues su trasero y patas posteriores ya no forman parte de su cuerpo al haber sido mutilado.\";s:6:\"img_hp\";s:0:\"\";}}'),
