	(6974,725,'repeatable_fields_2','a:1:{i:0;a:5:{s:13:\"texto_espanol\";s:293:\"<i>Itzamna’</i> extiende su dedo en la viñeta en señal de habla o discurso, mientras que <i>Ahan(?)</i> parece escuchar con atención. El primero usa un chal y un yelmo de lagarto combinado con otro animal, mientras el segundo luce en el tocado su característico tamal y hojas de mazorca.\";s:10:\"texto_maya\";s:0:\"\";s:6:\"img_hp\";s:0:\"\";s:12:\"coordenada_x\";s:0:\"\";s:12:\"coordenada_y\";s:0:\"\";}}'),
