	(6993,728,'repeatable_fields_2','a:1:{i:0;a:5:{s:13:\"texto_espanol\";s:290:\"En la primera viñeta aparece el búho (<i>kuy</i>), quien está asociado con el aspecto inframundano del dios L; lleva sobre la cabeza el signo de % -vinculado con la muerte- del cual salen plumas con manchas oscuras. Estas últimas aparentemente insinúan que se trata de un ave nocturna.\";s:10:\"texto_maya\";s:0:\"\";s:6:\"img_hp\";s:0:\"\";s:12:\"coordenada_x\";s:0:\"\";s:12:\"coordenada_y\";s:0:\"\";}}'),
