	(7364,887,'repeatable_fields_2','a:1:{i:0;a:5:{s:13:\"texto_espanol\";s:246:\"En la escena <i>Chaak</i> tiene parte del cuerpo sumergido en un depósito de agua, presenta la cabeza virada hacia arriba y sostiene el hacha. Un número de distancia negro 20 conduce a la fecha del siguiente pronóstico, que es <1 <i>ahau</i>>.\";s:10:\"texto_maya\";s:0:\"\";s:6:\"img_hp\";s:0:\"\";s:12:\"coordenada_x\";s:0:\"\";s:12:\"coordenada_y\";s:0:\"\";}}'),
