	(7871,1046,'repeatable_fields_2','a:1:{i:0;a:5:{s:13:\"texto_espanol\";s:193:\"<i>Chaak</i> está de pie en actitud de avanzar o caminar. El agua le llega hasta las rodillas. Sobre su puño cerrado hay dos jeroglíficos <i>kab</i>, ‘abeja, mundo, tierra’ o ‘miel’.\";s:10:\"texto_maya\";s:0:\"\";s:6:\"img_hp\";s:0:\"\";s:12:\"coordenada_x\";s:0:\"\";s:12:\"coordenada_y\";s:0:\"\";}}'),
