	(7887,1049,'repeatable_fields_2','a:1:{i:0;a:5:{s:13:\"texto_espanol\";s:195:\"Bajo el texto encontramos una imagen arrodillada del dios de la lluvia <i>Chaak</i>, quien emerge de las fauces de un gran ofidio sinuoso al tiempo que posiblemente porta un cuchillo excéntrico.\";s:10:\"texto_maya\";s:0:\"\";s:6:\"img_hp\";s:0:\"\";s:12:\"coordenada_x\";s:0:\"\";s:12:\"coordenada_y\";s:0:\"\";}}'),
