	(8296,1063,'repeatable_fields_2','a:1:{i:0;a:5:{s:13:\"texto_espanol\";s:193:\"La primera viñeta representa a <i>Chaak</i> navegando sobre un río. En la frente de <i>Chaak</i> apreciamos un tamal de pavo, que puede aludir a su pronóstico o puede simbolizar una ofrenda.\";s:10:\"texto_maya\";s:0:\"\";s:6:\"img_hp\";s:0:\"\";s:12:\"coordenada_x\";s:0:\"\";s:12:\"coordenada_y\";s:0:\"\";}}'),
